from feature_gate import gate_enabled


def test_explicit_false_values_are_disabled():
    name = "CHILI_EXPERIMENTAL_GATE"
    for value in ("0", "false", "no", "off", ""):
        assert gate_enabled({name: value}, name) is False


def test_true_values_are_enabled_case_insensitively():
    name = "CHILI_EXPERIMENTAL_GATE"
    for value in ("1", "true", "YES", "On"):
        assert gate_enabled({name: value}, name) is True
